//   - User turns are wrapped with [INST] / [/INST] markers.
//   - The system message (if present) is prepended inline to the first user turn,
//     separated by "\n\n" — there is no dedicated [SYSTEM_PROMPT] token.
//   - Assistant turns end with </s>.
// This handler delegates prompt rendering to the Jinja template and then installs
// a simple PEG parser that captures the assistant's reply as plain content.
static common_chat_params common_chat_params_init_mistral_instruct_v3(
        const common_chat_template &          tmpl,
        const autoparser::generation_params & inputs) {
    common_chat_params data;

    // Let the Jinja template handle [INST]/[/INST] wrapping, system message
    // prepending, and </s> insertion — we just need the rendered string.
    data.prompt = common_chat_template_direct_apply_impl(tmpl, inputs);
    data.format = COMMON_CHAT_FORMAT_PEG_NATIVE;

    auto parser = build_chat_peg_parser([&](common_chat_peg_builder & p) {
        // Skip the trailing generation prompt (empty for this format) then
        // capture the entire assistant reply as content.
        return p.literal(inputs.generation_prompt) + p.content(p.rest());
    });
    data.parser = parser.save();

    return data;
}

